    stack<Node> s;
    set<string> visited;
    s.push(*start);
    while (!s.empty()) {
        Node current  = s.top();
        s.pop();
        cout << current.name << endl;
        visited.insert(current.name);

        foreach (Arc * arc in current.arcs) {
